import 'package:flutter/material.dart';import 'design/astride_theme.dart';import 'screens/login_screen.dart';
import 'screens/change_password_screen.dart';import 'screens/partner_shell.dart';import 'services/api_client.dart';import 'services/session_store.dart';import 'state/partner_controller.dart';
void main(){WidgetsFlutterBinding.ensureInitialized();final c=PartnerController(ApiClient(),const SessionStore())..bootstrap();runApp(App(c));}class App extends StatelessWidget{const App(this.c,{super.key});final PartnerController c;@override Widget build(BuildContext x)=>ListenableBuilder(listenable:c,builder:(_,__)=>MaterialApp(debugShowCheckedModeBanner:false,title:'ASTRIDE Partner',theme:buildAstrideTheme(),home:c.session==null?LoginScreen(controller:c):PartnerShell(c:c)));}
